import{_ as i,C as a,o as s,c as l,ae as b,E as r,j as d,a as e}from"./chunks/framework.DNDrU9L4.js";const y=JSON.parse('{"title":"ハッピー世界！ — 가사로 배우기","description":"","frontmatter":{},"headers":[],"relativePath":"japanese/lyrics/happy-sekai.md","filePath":"japanese/lyrics/happy-sekai.md"}'),p={name:"japanese/lyrics/happy-sekai.md"};function u(c,t,k,q,m,f){const o=a("RomajiToggle"),n=a("Flashcard"),h=a("Quiz");return s(),l("div",null,[t[0]||(t[0]=b('<h1 id="ハッピー世界-—-가사로-배우기" tabindex="-1">ハッピー世界！ — 가사로 배우기 <a class="header-anchor" href="#ハッピー世界-—-가사로-배우기" aria-label="Permalink to &quot;ハッピー世界！ — 가사로 배우기&quot;">​</a></h1><h2 id="곡-소개" tabindex="-1">곡 소개 <a class="header-anchor" href="#곡-소개" aria-label="Permalink to &quot;곡 소개&quot;">​</a></h2><p>2025년 1월 3rd 싱글. 개성을 축하하는 노래입니다. &quot;귀여움&quot;은 하나가 아니라 무한한 정의가 있다는 메시지를 담았습니다. 나에서 너에게, 너에서 세계로 기쁨과 미소를 전하자는 테마로, 다양한 개성을 가진 멤버들이 각자의 방식으로 빛나는 모습을 그립니다. 시행착오를 거듭해도 포기하지 않는 강인한 의지도 담겨 있습니다.</p><hr><h2 id="타이틀-분석" tabindex="-1">타이틀 분석 <a class="header-anchor" href="#타이틀-분석" aria-label="Permalink to &quot;타이틀 분석&quot;">​</a></h2><table tabindex="0"><thead><tr><th>단어</th><th>읽기</th><th>뜻</th></tr></thead><tbody><tr><td>ハッピー</td><td>해피</td><td>Happy (영어)</td></tr><tr><td>世界</td><td>세카이</td><td>세계</td></tr></tbody></table><p><strong>전체 해석</strong>: &quot;행복한 세계!&quot; / &quot;세계를 행복하게!&quot;</p><blockquote><p><strong>포인트</strong>: 「世界」는 「세카이」로 읽습니다. 세(世) + 카이(界)의 조합으로, 세계/온 세상을 의미합니다. ハッピー와 세카이를 합쳐 「행복을 온 세상에」라는 이중적 의미를 담고 있습니다.</p></blockquote><hr><h2 id="곡에서-배우는-단어" tabindex="-1">곡에서 배우는 단어 <a class="header-anchor" href="#곡에서-배우는-단어" aria-label="Permalink to &quot;곡에서 배우는 단어&quot;">​</a></h2><table tabindex="0"><thead><tr><th>일본어</th><th>읽기</th><th>뜻</th><th>예문</th></tr></thead><tbody><tr><td>世界</td><td>세카이</td><td>세계</td><td>世界中に笑顔を届けたい。(세계에 미소를 전하고 싶다.)</td></tr><tr><td>幸せ</td><td>시아와세</td><td>행복</td><td>幸せな毎日を。(행복한 매일을.)</td></tr><tr><td>笑顔</td><td>에가오</td><td>미소, 웃는 얼굴</td><td>笑顔が広がる。(미소가 퍼진다.)</td></tr><tr><td>届ける</td><td>토도케루</td><td>전하다, 닿게 하다</td><td>気持ちを届けたい。(마음을 전하고 싶다.)</td></tr><tr><td>可愛い</td><td>카와이이</td><td>귀여운</td><td>可愛いって何だろう？(귀여움이란 뭘까?)</td></tr><tr><td>無限</td><td>무겐</td><td>무한</td><td>可愛いは無限大！(귀여움은 무한대!)</td></tr><tr><td>個性</td><td>코세이</td><td>개성</td><td>個性を大切に。(개성을 소중히.)</td></tr><tr><td>自分</td><td>지분</td><td>자기 자신</td><td>自分らしく輝く。(자신답게 빛난다.)</td></tr><tr><td>毎日</td><td>마이니치</td><td>매일</td><td>毎日がハッピー！(매일이 행복!)</td></tr><tr><td>最高</td><td>사이코</td><td>최고</td><td>今日も最高の一日！(오늘도 최고의 하루!)</td></tr><tr><td>挑戦</td><td>쵸센</td><td>도전</td><td>新しいことに挑戦する。(새로운 것에 도전한다.)</td></tr><tr><td>試行錯誤</td><td>시코사쿠고</td><td>시행착오</td><td>試行錯誤しながら成長する。(시행착오를 겪으며 성장한다.)</td></tr><tr><td>欲張り</td><td>요쿠바리</td><td>욕심쟁이, 탐욕스러운</td><td>夢に欲張りでいい！(꿈에 욕심쟁이여도 돼!)</td></tr><tr><td>素敵</td><td>스테키</td><td>멋진, 훌륭한</td><td>素敵な笑顔だね。(멋진 미소네.)</td></tr><tr><td>輝く</td><td>카가야쿠</td><td>빛나다</td><td>自分らしく輝こう。(자신답게 빛나자.)</td></tr><tr><td>みんな</td><td>민나</td><td>모두</td><td>みんなで幸せになろう！(모두 함께 행복해지자!)</td></tr><tr><td>特別</td><td>토쿠베츠</td><td>특별한</td><td>あなたは特別な存在。(당신은 특별한 존재.)</td></tr><tr><td>髪型</td><td>카미가타</td><td>헤어스타일</td><td>髪型を変えてみよう！(헤어스타일을 바꿔보자!)</td></tr></tbody></table><hr><h2 id="핵심-문법-3가지" tabindex="-1">핵심 문법 3가지 <a class="header-anchor" href="#핵심-문법-3가지" aria-label="Permalink to &quot;핵심 문법 3가지&quot;">​</a></h2><h3 id="_1-を届けたい-를-전하고-싶다" tabindex="-1">1. ～を届けたい (～를 전하고 싶다) <a class="header-anchor" href="#_1-を届けたい-를-전하고-싶다" aria-label="Permalink to &quot;1. ～を届けたい (～를 전하고 싶다)&quot;">​</a></h3><p>「～たい」는 1그룹/2그룹 동사의 ます형 어간에 붙여서 &quot;~하고 싶다&quot;는 희망을 표현합니다.</p><table tabindex="0"><thead><tr><th>동사</th><th>ます형 어간</th><th>～たい</th><th>뜻</th></tr></thead><tbody><tr><td>届ける</td><td>届け</td><td>届けたい</td><td>전하고 싶다</td></tr><tr><td>笑う</td><td>笑い</td><td>笑いたい</td><td>웃고 싶다</td></tr><tr><td>輝く</td><td>輝き</td><td>輝きたい</td><td>빛나고 싶다</td></tr><tr><td>伝える</td><td>伝え</td><td>伝えたい</td><td>전달하고 싶다</td></tr></tbody></table><p><strong>응용</strong>:</p><table tabindex="0"><thead><tr><th>일본어</th><th>뜻</th></tr></thead><tbody><tr><td>幸せを届けたい</td><td>행복을 전하고 싶다</td></tr><tr><td>笑顔を届けたい</td><td>미소를 전하고 싶다</td></tr><tr><td>世界に幸せを届けたい</td><td>세계에 행복을 전하고 싶다</td></tr></tbody></table><hr><h3 id="_2-って何-이란-뭐야-—-구어체-의문" tabindex="-1">2. ～って何？ (～이란 뭐야?) — 구어체 의문 <a class="header-anchor" href="#_2-って何-이란-뭐야-—-구어체-의문" aria-label="Permalink to &quot;2. ～って何？ (～이란 뭐야?) — 구어체 의문&quot;">​</a></h3><p>「って」는 「とは」의 구어체입니다. 어떤 것의 정의나 의미를 물을 때 씁니다.</p><table tabindex="0"><thead><tr><th>구어체</th><th>문어체</th><th>뜻</th></tr></thead><tbody><tr><td>可愛いって何？</td><td>可愛いとは何ですか？</td><td>귀여움이란 뭐야?</td></tr><tr><td>幸せって何？</td><td>幸せとは何ですか？</td><td>행복이란 뭐야?</td></tr><tr><td>個性って何？</td><td>個性とは何ですか？</td><td>개성이란 뭐야?</td></tr></tbody></table><blockquote><p><strong>포인트</strong>: って는 매우 구어체적인 표현입니다. 친구끼리 대화하거나 노래 가사, SNS에서 자주 볼 수 있습니다. 정중한 상황에서는 とは를 사용하세요.</p></blockquote><hr><h3 id="_3-から-へ-에서-에게-—-방향과-전달의-표현" tabindex="-1">3. ～から～へ (～에서 ～에게) — 방향과 전달의 표현 <a class="header-anchor" href="#_3-から-へ-에서-에게-—-방향과-전달의-표현" aria-label="Permalink to &quot;3. ～から～へ (～에서 ～에게) — 방향과 전달의 표현&quot;">​</a></h3><p>「から」는 출발점, 「へ」는 방향/도착점을 나타냅니다. 이 곡의 핵심 테마인 &quot;나에서 너에게, 너에서 세계로&quot;를 표현하는 패턴입니다.</p><table tabindex="0"><thead><tr><th>일본어</th><th>뜻</th></tr></thead><tbody><tr><td>私からあなたへ</td><td>나에서 너에게</td></tr><tr><td>あなたから世界へ</td><td>너에서 세계로</td></tr><tr><td>笑顔を私からあなたへ届けたい</td><td>미소를 나에서 너에게 전하고 싶다</td></tr></tbody></table><p><strong>から vs へ 비교</strong>:</p><table tabindex="0"><thead><tr><th>조사</th><th>역할</th><th>예시</th></tr></thead><tbody><tr><td>から</td><td>출발점 (~에서, ~부터)</td><td>東京から (도쿄에서)</td></tr><tr><td>へ</td><td>방향/목적지 (~에게, ~으로)</td><td>世界へ (세계로)</td></tr><tr><td>に</td><td>도착점 (~에, ~에게)</td><td>あなたに (당신에게)</td></tr></tbody></table><hr><h2 id="문화-노트" tabindex="-1">문화 노트 <a class="header-anchor" href="#문화-노트" aria-label="Permalink to &quot;문화 노트&quot;">​</a></h2><h3 id="큐티스트리트의-「kawaii-maker」-컨셉" tabindex="-1">큐티스트리트의 「KAWAII MAKER」 컨셉 <a class="header-anchor" href="#큐티스트리트의-「kawaii-maker」-컨셉" aria-label="Permalink to &quot;큐티스트리트의 「KAWAII MAKER」 컨셉&quot;">​</a></h3><p>큐티스트리트는 하라주쿠(原宿)에서 세계로 「カワイイ」를 발신한다는 컨셉을 갖고 있습니다.</p><ul><li><strong>하라주쿠(原宿)</strong>: 도쿄 하라주쿠는 카와이이 패션과 스트리트 컬처의 발신지. 다케시타도리(竹下通り)는 독특한 패션 아이템으로 가득</li><li><strong>KAWAII MAKER</strong>: &quot;카와이이를 만드는 사람들&quot;이라는 의미. 각자의 개성으로 세계에 귀여움을 발신</li><li><strong>무한한 카와이이</strong>: ハッピー世界가 말하듯, 귀여움의 형태는 무한합니다. 긴 머리도, 짧은 머리도, 활발한 성격도, 조용한 성격도 모두 귀여울 수 있다는 메시지</li></ul><h3 id="일본어의-외래어-활용" tabindex="-1">일본어의 외래어 활용 <a class="header-anchor" href="#일본어의-외래어-활용" aria-label="Permalink to &quot;일본어의 외래어 활용&quot;">​</a></h3><p>이 곡 제목처럼 일본어는 영어 등 외래어를 적극적으로 활용합니다.</p><table tabindex="0"><thead><tr><th>원어</th><th>일본어 표기</th><th>사용 예</th></tr></thead><tbody><tr><td>Happy</td><td>ハッピー</td><td>ハッピーな気分 (행복한 기분)</td></tr><tr><td>Cute</td><td>キュート</td><td>キュートなスタイル (귀여운 스타일)</td></tr><tr><td>Challenge</td><td>チャレンジ</td><td>チャレンジ精神 (도전 정신)</td></tr><tr><td>Style</td><td>スタイル</td><td>自分らしいスタイル (자신다운 스타일)</td></tr></tbody></table><hr><h2 id="핵심-표현-발음-가이드" tabindex="-1">핵심 표현 발음 가이드 <a class="header-anchor" href="#핵심-표현-발음-가이드" aria-label="Permalink to &quot;핵심 표현 발음 가이드&quot;">​</a></h2>',39)),r(o,{items:[{japanese:"ハッピー世界",romaji:"happii sekai",meaning:"행복한 세계!"},{japanese:"可愛いって何だろう",romaji:"kawaii tte nan darou",meaning:"귀여움이란 뭘까?"},{japanese:"笑顔を届けたい",romaji:"egao wo todoketai",meaning:"미소를 전하고 싶다"},{japanese:"私からあなたへ",romaji:"watashi kara anata e",meaning:"나에서 너에게"},{japanese:"自分らしく輝こう",romaji:"jibun rashiku kagayakou",meaning:"자신답게 빛나자"},{japanese:"可愛いは無限大",romaji:"kawaii wa mugendai",meaning:"귀여움은 무한대!"}]}),t[1]||(t[1]=d("h2",{id:"단어-플래시카드",tabindex:"-1"},[e("단어 플래시카드 "),d("a",{class:"header-anchor",href:"#단어-플래시카드","aria-label":'Permalink to "단어 플래시카드"'},"​")],-1)),t[2]||(t[2]=d("p",null,"클릭해서 뒤집어 보세요!",-1)),r(n,{cardSetId:"lyrics-happy-sekai",cards:[{front:"世界 (せかい)",back:"세계"},{front:"幸せ (しあわせ)",back:"행복"},{front:"笑顔 (えがお)",back:"미소, 웃는 얼굴"},{front:"届ける (とどける)",back:"전하다, 닿게 하다"},{front:"無限 (むげん)",back:"무한"},{front:"個性 (こせい)",back:"개성"},{front:"自分 (じぶん)",back:"자기 자신"},{front:"最高 (さいこう)",back:"최고"},{front:"挑戦 (ちょうせん)",back:"도전"},{front:"試行錯誤 (しこうさくご)",back:"시행착오"},{front:"欲張り (よくばり)",back:"욕심쟁이"},{front:"素敵 (すてき)",back:"멋진, 훌륭한"},{front:"特別 (とくべつ)",back:"특별한"},{front:"毎日 (まいにち)",back:"매일"},{front:"髪型 (かみがた)",back:"헤어스타일"}]}),t[3]||(t[3]=d("hr",null,null,-1)),t[4]||(t[4]=d("h2",{id:"가사-퀴즈",tabindex:"-1"},[e("가사 퀴즈 "),d("a",{class:"header-anchor",href:"#가사-퀴즈","aria-label":'Permalink to "가사 퀴즈"'},"​")],-1)),t[5]||(t[5]=d("p",null,"8문제에 도전! 어휘와 문법을 함께 확인해 봅시다.",-1)),r(h,{quizId:"lyrics-happy-sekai",questions:[{q:"「世界」(せかい)의 뜻은?",options:["나라","도시","세계","우주"],answer:2},{q:"「幸せ」(しあわせ)의 뜻은?",options:["슬픔","행복","외로움","분노"],answer:1},{q:"「届けたい」의 뜻은?",options:["전했다","전하지 않겠다","전하고 싶다","전할 수 있다"],answer:2},{q:"「個性」(こせい)의 뜻은?",options:["성격","개성","특기","취미"],answer:1},{q:"「可愛いって何？」를 정중하게 바꾸면?",options:["可愛いですか？","可愛いとは何ですか？","可愛いになりますか？","可愛いでしょうか？"],answer:1},{q:"「私からあなたへ」의 뜻은?",options:["나와 너","나를 위해 너","나에서 너에게","나도 너도"],answer:2},{q:"「試行錯誤」(しこうさくご)의 뜻은?",options:["도전과 응전","시행착오","성공과 실패","노력과 결과"],answer:1},{q:"「欲張り」(よくばり)의 뜻은?",options:["노력가","꿈쟁이","욕심쟁이","낙천가"],answer:2}]})])}const x=i(p,[["render",u]]);export{y as __pageData,x as default};
